// ─── ROUTER ────────────────────────────────────────────────────────────────
// Uses React state — no window.location, works inside iframe/artifact
function useRouter() {
  const [page, setPageState] = useState("/");
  const setPage = (path) => {
    setPageState(path);
    window.scrollTo({ top: 0, behavior: "instant" });
  };
  return [page, setPage];
}


