// ─── LOGO ───────────────────────────────────────────────────────────────────
// Concept: the DA•RA mark as a precision instrument stamp —
// two vertical bars (D and A columns) with a connecting arc,
// representing a drafting compass. Wordmark: DA•RA STUDIO spaced-out,
// no subtitle line.
// ─── DA•RA LOGO — faithful SVG recreation of the original mark ────────────
// Structure: outer square frame + thick right column + circle (d letterform)
// All in #C9A96E, transparent background
// ─── DA•RA Mark — real uploaded logo, white made transparent via CSS ─────────
const LOGO_B64 = "data:image/jpeg;base64,";

// ─── About Section Images ─────────────────────────────────────────────────────
const ABOUT_IMG1 = "data:image/png;base64,";
const ABOUT_IMG2 = "data:image/png;base64,";


function DaraMarkSVG({ size = 36 }) {
  // Faithful recreation of uploaded DA•RA logo:
  // - Outer square frame (thick border ~10%)
  // - RIGHT side: solid vertical column (~22% width, full inner height)
  // - LEFT side: open circle RING (d letterform) — ring not filled
  // Transparent background, gold #C9A96E
  // Uses SVG mask — most reliable cross-browser approach for compound shapes

  const uid = "dara" + String(size);

  return (
    <svg width={size} height={size} viewBox="0 0 100 100"
      xmlns="http://www.w3.org/2000/svg"
      style={{ display:"block", flexShrink:0 }}>
      <defs>
        <mask id={uid}>
          {/* Everything starts white (visible gold) */}
          <rect width="100" height="100" fill="white"/>
          {/* Cut frame interior — only the left+middle area (not the right column) */}
          <rect x="10" y="10" width="62" height="80" fill="black"/>
          {/* Restore ring outer area (puts gold back for the circle) */}
          <circle cx="41" cy="50" r="30" fill="white"/>
          {/* Cut ring interior (punches the hole — makes it a ring not a disc) */}
          <circle cx="41" cy="50" r="19" fill="black"/>
        </mask>
      </defs>
      {/* Single gold rect, shaped entirely by the mask above */}
      <rect width="100" height="100" fill="#C9A96E" mask={`url(#${uid})`}/>
    </svg>
  );
}

function Logo({ scale = 1, dark = false }) {
  const text = dark ? "#1a1611" : TH;
  const sz = Math.round(36 * scale);
  return (
    <div style={{ display: "flex", alignItems: "center", gap: Math.round(sz * 0.38), userSelect: "none" }}>
      <DaraMarkSVG size={sz}/>
      <div style={{
        fontFamily: "'Cormorant Garamond', Georgia, serif",
        fontSize: Math.round(sz * 0.55),
        fontWeight: 700,
        letterSpacing: "0.16em",
        color: text,
        lineHeight: 1,
        display: "flex", alignItems: "center", gap: Math.round(sz * 0.1),
      }}>
        <span>DA</span>
        <span style={{ color: G, fontWeight: 400, fontSize: Math.round(sz * 0.42) }}>•</span>
        <span>RA</span>
        <span style={{ fontWeight: 400, fontSize: Math.round(sz * 0.5), letterSpacing: "0.18em", marginLeft: Math.round(sz * 0.1), color: dark ? "#555" : "#9a9080" }}>STUDIO</span>
      </div>
    </div>
  );
}

