// ─── SCROLL REVEAL ──────────────────────────────────────────────────────────
function useReveal() {
  const ref = useRef(null);
  const [v, setV] = useState(false);
  useEffect(() => {
    const el = ref.current; if (!el) return;
    const o = new IntersectionObserver(([e]) => { if (e.isIntersecting) { setV(true); o.disconnect(); } }, { threshold: 0.08 });
    o.observe(el);
    return () => o.disconnect();
  }, []);
  return [ref, v];
}
function Rev({ children, d = 0 }) {
  const [ref, v] = useReveal();
  return <div ref={ref} style={{ opacity: v?1:0, transform: v?"none":"translateY(20px)", transition:`opacity .7s ease ${d}s,transform .7s ease ${d}s` }}>{children}</div>;
}

