// ─── Phone formatters ──────────────────────────────────────────────────────
function fmtUSPhone(raw) {
  const d = raw.replace(/\D/g,"").slice(0,11);
  if(!d.length) return "";
  if(d.length<=1) return `+${d}`;
  if(d.length<=4) return `+${d[0]} (${d.slice(1)}`;
  if(d.length<=7) return `+${d[0]} (${d.slice(1,4)}) ${d.slice(4)}`;
  return `+${d[0]} (${d.slice(1,4)}) ${d.slice(4,7)}-${d.slice(7)}`;
}
function fmtBRPhone(raw) {
  const d = raw.replace(/\D/g,"").slice(0,13);
  if(!d.length) return "";
  if(d.length<=2) return `+${d}`;
  if(d.length<=4) return `+${d.slice(0,2)} (${d.slice(2)}`;
  if(d.length<=9) return `+${d.slice(0,2)} (${d.slice(2,4)}) ${d.slice(4)}`;
  return `+${d.slice(0,2)} (${d.slice(2,4)}) ${d.slice(4,9)}-${d.slice(9)}`;
}

// ─── Estimate calculator ───────────────────────────────────────────────────
function calcEstimate({ region, width, length, levels, engagement, viz3dExterior, room3d, rushService }) {
  const w = parseFloat(width)||0, l = parseFloat(length)||0;
  const baseArea = w * l;
  const isBR = region === "br";
  const unit = isBR ? "m²" : "sqft";
  const items = [];
  let subtotal = 0;

  if (baseArea <= 0 || !engagement) {
    return { low:0, high:0, subtotal:0, items:[], canCalculate:false, rushFee:0, rushPercent:0 };
  }

  if (engagement === "pdf_to_cad") {
    // PDF to CAD: $0.50/sqft, no floor additions, no 3D
    const c = baseArea * 0.50;
    subtotal += c;
    items.push({ label:`PDF to CAD Conversion (${baseArea.toLocaleString()} ${unit})`, value:c, hidden:false });
  } else if (engagement === "plans_only") {
    const c = baseArea * 0.80;
    subtotal += c;
    items.push({ label:`Floor Plans Only (${baseArea.toLocaleString()} ${unit})`, value:c, hidden:false });
  } else if (engagement === "full") {
    const c = baseArea * 1.60;
    subtotal += c;
    items.push({ label:`Ground Floor (${baseArea.toLocaleString()} ${unit})`, value:c, hidden:false });
    if (levels.includes("2nd")) {
      const c2 = baseArea * 1.10;
      subtotal += c2;
      items.push({ label:`2nd Floor (${baseArea.toLocaleString()} ${unit})`, value:c2, hidden:false });
    }
    if (levels.includes("basement")) {
      const cb = baseArea * 0.80;
      subtotal += cb;
      items.push({ label:`Basement (${baseArea.toLocaleString()} ${unit})`, value:cb, hidden:false });
    }
    if (levels.includes("attic")) {
      const ca = baseArea * 0.60;
      subtotal += ca;
      items.push({ label:`Attic (${baseArea.toLocaleString()} ${unit})`, value:ca, hidden:false });
    }
  }

  // 3D add-ons (only for full or plans_only)
  if (engagement !== "pdf_to_cad") {
    if (viz3dExterior) {
      if (engagement === "full") {
        items.push({ label:"3D Exterior Rendering", value:0, included:true, hidden:false });
      } else {
        subtotal += 450;
        items.push({ label:"3D Exterior Rendering", value:450, hidden:false });
      }
    }
    for (const r of (room3d||[])) {
      const lbl = r==="kitchen"?"3D Kitchen Design":r==="bathroom"?"3D Bathroom Design":"3D Laundry Design";
      subtotal += 350;
      items.push({ label:lbl, value:350, hidden:false });
    }
  }

  subtotal = Math.round(subtotal);

  // Rush fee
  const rushOpt = RUSH_OPTIONS.find(r=>r.value===rushService);
  const rushPercent = rushOpt?.rushPercent || 0;
  const rushFee = Math.round(subtotal * rushPercent / 100);

  const total = subtotal + rushFee;
  const low  = Math.round(total * 0.90);
  const high = Math.round(total * 1.10);

  if (rushFee > 0) {
    items.push({ label:`Rush Fee — ${rushOpt.label} (+${rushPercent}%)`, value:rushFee, hidden:false });
  }

  return { low, high, subtotal, items, canCalculate:true, rushFee, rushPercent };
}

function calcConfidence(f, filesCount, step) {
  let s = 0;
  if(f.region) s+=8;
  if(f.city?.trim()) s+=3;
  if(f.state?.trim()) s+=2;
  if(f.zip?.trim()) s+=2;
  if(f.name?.trim()) s+=10;
  if(f.email?.trim()) s+=5;
  if(f.role) s+=5;
  if(["Builder / Contractor","Architect","Developer"].includes(f.role)) s+=5;
  if(f.companyName?.trim()) s+=3;
  const area = (parseFloat(f.width)||0)*(parseFloat(f.length)||0);
  if(area>0) s+=20;
  if((f.levels||[]).length>1) s+=5;
  if((f.projectTypes||[]).length) s+=10;
  if(f.engagement) s+=12;
  if(filesCount) s+=5;
  s += Math.min(step*2,10);
  return Math.min(s,100);
}

// ─── InfoWrap — How We Work style expandable ℹ panel ─────────────────────
function FormInfoWrap({ children, text }) {
  const [open, setOpen] = useState(false);
  return (
    <span style={{position:"relative",display:"flex",flexDirection:"column"}}>
      <span style={{display:"flex",alignItems:"center"}}>
        {children}
        <button
          type="button"
          onClick={e=>{e.stopPropagation();setOpen(v=>!v);}}
          style={{width:18,height:18,borderRadius:"50%",marginLeft:7,flexShrink:0,
            border:`1.5px solid ${open?C.primary:C.primaryHex}`,
            background:open?C.primaryLight:"transparent",
            color:open?C.primary:C.primaryHex,
            fontSize:11,fontWeight:700,cursor:"pointer",
            display:"inline-flex",alignItems:"center",justifyContent:"center",
            lineHeight:1,padding:0,fontFamily:"Georgia,serif",
            transition:"all 0.15s"}}
          aria-label={open?"Hide details":"Show details"}>
          ℹ
        </button>
      </span>
      <span style={{maxHeight:open?300:0,overflow:"hidden",
        transition:"max-height 0.32s cubic-bezier(0.4,0,0.2,1), opacity 0.25s",
        opacity:open?1:0}}>
        <span style={{display:"block",background:"rgba(15,12,8,0.95)",border:"1px solid rgba(201,169,110,0.3)",
          borderRadius:2,padding:"14px 17px",marginTop:8,fontSize:13,
          color:"#e0d8c8",lineHeight:1.72,boxShadow:"0 8px 32px rgba(0,0,0,0.6)"}}>
          {text}
        </span>
      </span>
    </span>
  );
}

